/**
 * Source Sans 3 font data for jsPDF embedding.
 * Weights: Regular (400), SemiBold (600), Bold (700).
 * Load this file before pdf.js.
 */
(function () {
  if (typeof window === 'undefined') return;

  window.InvioPDFFonts = {
    medium: '',
    regular: '',
    semibold: '',
    bold: ''
  };

  window.InvioPDFFonts.register = function (doc) {
    if (!doc || !doc.addFileToVFS || !doc.addFont) return false;
    try {
      doc.addFileToVFS('SourceSans3-Medium.ttf', window.InvioPDFFonts.medium);
      doc.addFileToVFS('SourceSans3-Regular.ttf', window.InvioPDFFonts.regular);
      doc.addFileToVFS('SourceSans3-SemiBold.ttf', window.InvioPDFFonts.semibold);
      doc.addFileToVFS('SourceSans3-Bold.ttf', window.InvioPDFFonts.bold);
      doc.addFont('SourceSans3-Medium.ttf', 'SourceSans3', 'medium');
      doc.addFont('SourceSans3-Regular.ttf', 'SourceSans3', 'normal');
      doc.addFont('SourceSans3-SemiBold.ttf', 'SourceSans3', 'semibold');
      doc.addFont('SourceSans3-Bold.ttf', 'SourceSans3', 'bold');
      return true;
    } catch (e) {
      return false;
    }
  };
})();
